  1→import { useState, useEffect, useCallback, useMemo, useRef } from "react";
  2→import { Box, useApp, useInput } from "ink";
  3→import { Spinner } from "@inkjs/ui";
  4→import type {
  5→  SessionInfo,
  6→  DisplayMessage,
  7→  DisplayItem,
  8→  TeamSnapshot,
  9→  DebugEntry,
 10→  SessionMeta,
 11→  SessionTotals,
 12→} from "./api.js";
 13→import { api } from "./api.js";
 14→import { useSSE } from "./useSSE.js";
 15→import { useToggleSet } from "../../shared/hooks/useToggleSet.js";
 16→import { SessionPicker } from "./components/SessionPicker.js";
 17→import { MessageList } from "./components/MessageList.js";
 18→import { DetailView } from "./components/DetailView.js";
 19→import { TeamBoard } from "./components/TeamBoard.js";
 20→import { DebugViewer } from "./components/DebugViewer.js";
 21→import { InfoBar } from "./components/InfoBar.js";
 22→import { KeybindBar } from "./components/KeybindBar.js";
 23→import { ProjectTree, useProjectEntries } from "./components/ProjectTree.js";
 24→import { projectKey } from "./lib/projectKey.js";
 25→
 26→type ViewState = "picker" | "list" | "detail" | "team" | "debug";
 27→
 28→const EMPTY_META: SessionMeta = { cwd: "", git_branch: "", permission_mode: "" };
 29→const EMPTY_TOTALS: SessionTotals = {
 30→  total_tokens: 0,
 31→  input_tokens: 0,
 32→  output_tokens: 0,
 33→  cache_read_tokens: 0,
 34→  cache_creation_tokens: 0,
 35→  cost_usd: 0,
 36→  model: "",
 37→};
 38→
 39→export function App() {
 40→  const { exit } = useApp();
 41→  const [view, setView] = useState<ViewState>("picker");
 42→
 43→  // ---- Picker state ----
 44→  const [allSessions, setAllSessions] = useState<SessionInfo[]>([]);
 45→  const [pickerLoading, setPickerLoading] = useState(true);
 46→  const [pickerError, setPickerError] = useState("");
 47→  const [selectedProject, setSelectedProject] = useState<string | null>(null);
 48→  const [sidebarFocused, setSidebarFocused] = useState(false);
 49→  const [sidebarHighlight, setSidebarHighlight] = useState(0);
 50→
 51→  const projectEntries = useProjectEntries(allSessions);
 52→
 53→  const pickerSessions = useMemo(() => {
 54→    if (selectedProject === null) return allSessions;
 55→    return allSessions.filter((s) => projectKey(s.path) === selectedProject);
 56→  }, [allSessions, selectedProject]);
 57→
 58→  useEffect(() => {
 59→    let cancelled = false;
 60→    const attempt = async (retries: number): Promise<void> => {
 61→      try {
 62→        const d = await api.getProjectDirs();
 63→        if (cancelled) return;
 64→        if (d.length === 0) {
 65→          setPickerError("No project directories found. Run the desktop app first to configure.");
 66→          setPickerLoading(false);
 67→          return;
 68→        }
 69→        const list = await api.discoverSessions(d);
 70→        if (cancelled) return;
 71→        setAllSessions(list);
 72→        setPickerLoading(false);
 73→        await api.watchPicker(d);
 74→      } catch (e) {
 75→        if (cancelled) return;
 76→        if (retries > 0) {
 77→          await new Promise((r) => setTimeout(r, 1000));
 78→          if (!cancelled) return attempt(retries - 1);
 79→        }
 80→        setPickerError(`Cannot connect to backend. Is the app running?\n${e}`);
 81→        setPickerLoading(false);
 82→      }
 83→    };
 84→    attempt(10);
 85→    return () => {
 86→      cancelled = true;
 87→      api.unwatchPicker().catch(() => {});
 88→    };
 89→  }, []);
 90→
 91→  useSSE<{ sessions: SessionInfo[] }>(
 92→    "picker-update",
 93→    useCallback((payload) => {
 94→      if (payload.sessions) setAllSessions(payload.sessions);
 95→    }, []),
 96→  );
 97→
 98→  // ---- Session state ----
 99→  const [sessionPath, setSessionPath] = useState("");
100→  const [messages, setMessages] = useState<DisplayMessage[]>([]);
101→  const [teams, setTeams] = useState<TeamSnapshot[]>([]);
102→  const [ongoing, setOngoing] = useState(false);
103→  const [meta, setMeta] = useState<SessionMeta>(EMPTY_META);
104→  const [totals, setTotals] = useState<SessionTotals>(EMPTY_TOTALS);
105→  const [loading, setLoading] = useState(false);
106→  const [debugEntries, setDebugEntries] = useState<DebugEntry[]>([]);
107→
108→  const expandedMessages = useToggleSet();
109→  const expandedItems = useToggleSet();
110→
111→  const [pickerSelected, setPickerSelected] = useState(0);
112→  const [selectedMessage, setSelectedMessage] = useState(0);
113→  const [selectedItem, setSelectedItem] = useState(0);
114→  const [debugSelected, setDebugSelected] = useState(0);
115→
116→  // Subagent drill-down: when entering a subagent item, we show its
117→  // subagent_messages as a message list. The user can then Enter a message
118→  // to see its items. This mirrors the web's panel stack.
119→  const [subagentItem, setSubagentItem] = useState<DisplayItem | null>(null);
120→  const [subagentMsgIdx, setSubagentMsgIdx] = useState(0); // selected message in subagent list
121→  const [subagentDetailMsg, setSubagentDetailMsg] = useState<DisplayMessage | null>(null); // drilled into a msg
122→
123→  const loadSession = useCallback(
124→    async (path: string) => {
125→      setLoading(true);
126→      try {
127→        const result = await api.loadSession(path);
128→        setSessionPath(path);
129→        setMessages(result.messages);
130→        setTeams(result.teams);
131→        setOngoing(result.ongoing);
132→        setMeta(result.meta);
133→        setTotals(result.session_totals);
134→        setSelectedMessage(result.messages.length - 1);
135→        expandedMessages.clear();
136→        await api.watchSession(path);
137→      } catch {
138→        // ignore
139→      }
140→      setLoading(false);
141→    },
142→    [expandedMessages],
143→  );
144→
145→  useSSE<{
146→    messages: DisplayMessage[];
147→    ongoing: boolean;
148→    permission_mode: string;
149→    teams: TeamSnapshot[];
150→    session_totals: SessionTotals;
151→  }>(
152→    "session-update",
153→    useCallback((payload) => {
154→      setMessages(payload.messages);
155→      setOngoing(payload.ongoing);
156→      setTotals(payload.session_totals);
157→      if (payload.teams) setTeams(payload.teams);
158→      if (payload.permission_mode) {
159→        setMeta((m) => ({ ...m, permission_mode: payload.permission_mode }));
160→      }
161→    }, []),
162→  );
163→
164→  useEffect(() => {
165→    return () => {
166→      api.unwatchSession().catch(() => {});
167→    };
168→  }, []);
169→
170→  const handleSelectSession = useCallback(
171→    (s: SessionInfo) => {
172→      loadSession(s.path);
173→      setView("list");
174→      setSidebarFocused(false);
175→    },
176→    [loadSession],
177→  );
178→
179→  const handleSelectProject = useCallback((key: string | null) => {
180→    setSelectedProject(key);
181→    setSidebarFocused(false);
182→  }, []);
183→
184→  // ---- Single unified keyboard handler ----
185→  // Use a ref so the useInput effect never re-subscribes.
186→  // Ink's useInput puts inputHandler in its effect deps — if we pass a
187→  // new function each render, the stdin listener is removed and re-added
188→  // on every render, causing keystrokes to be lost in the gap.
189→  type Key = {
190→    upArrow: boolean;
191→    downArrow: boolean;
192→    leftArrow: boolean;
193→    rightArrow: boolean;
194→    return: boolean;
195→    escape: boolean;
196→    tab: boolean;
197→    backspace: boolean;
198→    delete: boolean;
199→    ctrl: boolean;
200→    shift: boolean;
201→    meta: boolean;
202→  };
203→  const inputHandlerRef = useRef<(input: string, key: Key) => void>(() => {});
204→  inputHandlerRef.current = (input: string, key: Key) => {
205→    // Sidebar navigation
206→    if (sidebarFocused && view === "picker") {
207→      if (input === "j" || key.downArrow) {
208→        setSidebarHighlight((i) => Math.min(i + 1, projectEntries.length - 1));
209→      } else if (input === "k" || key.upArrow) {
210→        setSidebarHighlight((i) => Math.max(i - 1, 0));
211→      } else if (key.return) {
212→        const entry = projectEntries[sidebarHighlight];
213→        if (entry && !entry.isGroup) handleSelectProject(entry.key);
214→      } else if (input === "l" || key.rightArrow || key.escape) {
215→        setSidebarFocused(false);
216→      } else if (input === "q") {
217→        exit();
218→      }
219→      return;
220→    }
221→
222→    switch (view) {
223→      case "list": {
224→        if (input === "h" || key.leftArrow) {
225→          setSidebarFocused(true);
226→        } else if (input === "j" || key.downArrow) {
227→          setSelectedMessage((i) => Math.min(i + 1, messages.length - 1));
228→        } else if (input === "k" || key.upArrow) {
229→          setSelectedMessage((i) => Math.max(i - 1, 0));
230→        } else if (input === "G") {
231→          setSelectedMessage(messages.length - 1);
232→        } else if (input === "g") {
233→          setSelectedMessage(0);
234→        } else if (key.tab) {
235→          expandedMessages.toggle(selectedMessage);
236→        } else if (key.return) {
237→          if (messages.length > 0 && messages[selectedMessage]) {
238→            setSelectedItem(0);
239→            expandedItems.clear();
240→            setSubagentItem(null);
241→            setSubagentDetailMsg(null);
242→            setView("detail");
243→          }
244→        } else if (input === "e") {
245→          const indices: number[] = [];
246→          messages.forEach((m, i) => {
247→            if (m.role === "claude") indices.push(i);
248→          });
249→          expandedMessages.addAll(indices);
250→        } else if (input === "c") {
251→          expandedMessages.clear();
252→        } else if (input === "t") {
253→          if (teams.length > 0) setView("team");
254→        } else if (input === "d") {
255→          if (sessionPath) {
256→            api
257→              .getDebugLog(sessionPath)
258→              .then(setDebugEntries)
259→              .catch(() => {});
260→            setDebugSelected(0);
261→            setView("debug");
262→          }
263→        } else if (input === "q" || key.escape) {
264→          setView("picker");
265→        }
266→        break;
267→      }
268→      case "detail": {
269→        if (subagentItem && !subagentDetailMsg) {
270→          // Viewing subagent message list
271→          const msgs = subagentItem.subagent_messages;
272→          if (input === "j" || key.downArrow) {
273→            setSubagentMsgIdx((i) => Math.min(i + 1, msgs.length - 1));
274→          } else if (input === "k" || key.upArrow) {
275→            setSubagentMsgIdx((i) => Math.max(i - 1, 0));
276→          } else if (key.return) {
277→            // Enter a message to see its items
278→            if (msgs[subagentMsgIdx]) {
279→              setSubagentDetailMsg(msgs[subagentMsgIdx]);
280→              setSelectedItem(0);
281→              expandedItems.clear();
282→            }
283→          } else if (input === "q" || key.escape) {
284→            setSubagentItem(null);
285→            setSubagentMsgIdx(0);
286→          }
287→        } else if (subagentDetailMsg) {
288→          // Viewing items of a subagent message
289→          const items = subagentDetailMsg.items || [];
290→          if (input === "j" || key.downArrow) {
291→            setSelectedItem((i) => Math.min(i + 1, items.length - 1));
292→          } else if (input === "k" || key.upArrow) {
293→            setSelectedItem((i) => Math.max(i - 1, 0));
294→          } else if (key.tab || key.return) {
295→            const item = items[selectedItem];
296→            if (key.return && item?.subagent_messages?.length > 0) {
297→              // Nested subagent — drill deeper
298→              setSubagentItem(item);
299→              setSubagentDetailMsg(null);
300→              setSubagentMsgIdx(0);
301→            } else {
302→              expandedItems.toggle(selectedItem);
303→            }
304→          } else if (input === "e") {
305→            expandedItems.addAll(items.map((_it, i) => i));
306→          } else if (input === "c") {
307→            expandedItems.clear();
308→          } else if (input === "q" || key.escape) {
309→            // Back to subagent message list
310→            setSubagentDetailMsg(null);
311→            setSubagentMsgIdx(0);
312→          }
313→        } else {
314→          // Top-level detail view (main message items)
315→          const items = messages[selectedMessage]?.items || [];
316→          if (input === "j" || key.downArrow) {
317→            setSelectedItem((i) => Math.min(i + 1, items.length - 1));
318→          } else if (input === "k" || key.upArrow) {
319→            setSelectedItem((i) => Math.max(i - 1, 0));
320→          } else if (key.tab) {
321→            expandedItems.toggle(selectedItem);
322→          } else if (key.return) {
323→            const item = items[selectedItem];
324→            if (item?.subagent_messages?.length > 0) {
325→              setSubagentItem(item);
326→              setSubagentMsgIdx(0);
327→              setSubagentDetailMsg(null);
328→            } else {
329→              expandedItems.toggle(selectedItem);
330→            }
331→          } else if (input === "e") {
332→            expandedItems.addAll(items.map((_it, i) => i));
333→          } else if (input === "c") {
334→            expandedItems.clear();
335→          } else if (input === "q" || key.escape) {
336→            setView("list");
337→          }
338→        }
339→        break;
340→      }
341→      case "debug": {
342→        if (input === "j" || key.downArrow) {
343→          setDebugSelected((i) => Math.min(i + 1, debugEntries.length - 1));
344→        } else if (input === "k" || key.upArrow) {
345→          setDebugSelected((i) => Math.max(i - 1, 0));
346→        } else if (input === "q" || key.escape) {
347→          setView("list");
348→        }
349→        break;
350→      }
351→      case "team": {
352→        if (input === "q" || key.escape) setView("list");
353→        break;
354→      }
355→      case "picker": {
356→        if (input === "h" || key.leftArrow) setSidebarFocused(true);
357→        else if (input === "j" || key.downArrow) {
358→          setPickerSelected((i) => Math.min(i + 1, pickerSessions.length - 1));
359→        } else if (input === "k" || key.upArrow) {
360→          setPickerSelected((i) => Math.max(i - 1, 0));
361→        } else if (input === "G") {
362→          setPickerSelected(pickerSessions.length - 1);
363→        } else if (input === "g") {
364→          setPickerSelected(0);
365→        } else if (key.return) {
366→          if (pickerSessions[pickerSelected]) {
367→            handleSelectSession(pickerSessions[pickerSelected]);
368→          }
369→        } else if (input === "q") {
370→          exit();
371→        }
372→        break;
373→      }
374→    }
375→  };
376→  // Stable function reference — never changes, so Ink's useInput effect never re-subscribes.
377→  const stableHandler = useCallback((input: string, key: Key) => {
378→    inputHandlerRef.current(input, key);
379→  }, []);
380→  useInput(stableHandler);
381→
382→  // ---- Render ----
383→  const renderView = () => {
384→    switch (view) {
385→      case "picker":
386→        return (
387→          <SessionPicker
388→            sessions={pickerSessions}
389→            loading={pickerLoading}
390→            error={pickerError}
391→            selectedIndex={pickerSelected}
392→          />
393→        );
394→      case "list":
395→        if (loading) {
396→          return (
397→            <Box padding={1}>
398→              <Spinner label="Loading session..." />
399→            </Box>
400→          );
401→        }
402→        return (
403→          <MessageList
404→            messages={messages}
405→            selectedIndex={selectedMessage}
406→            expandedSet={expandedMessages.set}
407→            ongoing={ongoing}
408→          />
409→        );
410→      case "detail": {
411→        if (subagentItem && !subagentDetailMsg) {
412→          // Show subagent's messages as a list
413→          return (
414→            <MessageList
415→              messages={subagentItem.subagent_messages}
416→              selectedIndex={subagentMsgIdx}
417→              expandedSet={expandedMessages.set}
418→              ongoing={subagentItem.subagent_ongoing}
419→            />
420→          );
421→        }
422→        if (subagentDetailMsg) {
423→          // Show a subagent message's items
424→          return (
425→            <DetailView
426→              message={subagentDetailMsg}
427→              selectedItem={selectedItem}
428→              expandedItems={expandedItems.set}
429→              ongoing={false}
430→              depth={1}
431→            />
432→          );
433→        }
434→        // Top-level message detail
435→        if (messages[selectedMessage]) {
436→          return (
437→            <DetailView
438→              message={messages[selectedMessage]}
439→              selectedItem={selectedItem}
440→              expandedItems={expandedItems.set}
441→              ongoing={ongoing && selectedMessage === messages.length - 1}
442→            />
443→          );
444→        }
445→        return null;
446→      }
447→      case "team":
448→        return <TeamBoard teams={teams} />;
449→      case "debug":
450→        return <DebugViewer entries={debugEntries} selectedIndex={debugSelected} />;
451→    }
452→  };
453→
454→  const termHeight = process.stdout.rows || 24;
455→
456→  return (
457→    <Box flexDirection="column" height={termHeight}>
458→      {sessionPath && view !== "picker" && (
459→        <InfoBar
460→          meta={meta}
461→          messages={messages}
462→          sessionTotals={totals}
463→          sessionPath={sessionPath}
464→          ongoing={ongoing}
465→        />
466→      )}
467→
468→      <Box flexDirection="row" flexGrow={1}>
469→        <ProjectTree
470→          sessions={allSessions}
471→          selectedProject={selectedProject}
472→          highlightedIndex={sidebarHighlight}
473→          isFocused={sidebarFocused}
474→        />
475→        <Box flexDirection="column" flexGrow={1}>
476→          {renderView()}
477→        </Box>
478→      </Box>
479→
480→      <KeybindBar
481→        view={view}
482→        hasTeams={teams.length > 0}
483→        position={
484→          view === "list"
485→            ? `${selectedMessage + 1}/${messages.length}`
486→            : view === "detail"
487→              ? subagentItem && !subagentDetailMsg
488→                ? `agent ${subagentMsgIdx + 1}/${subagentItem.subagent_messages.length}`
489→                : `${subagentDetailMsg ? "agent " : ""}${selectedItem + 1}/${(subagentDetailMsg ?? messages[selectedMessage])?.items.length || 0}`
490→              : view === "debug"
491→                ? `${debugSelected + 1}/${debugEntries.length}`
492→                : view === "picker"
493→                  ? `${pickerSelected + 1}/${pickerSessions.length}`
494→                  : undefined
495→        }
496→      />
497→    </Box>
498→  );
499→}
