 65→// --- Flattened virtual list ---
 66→
 67→// pickerItemType discriminates between session rows and group headers.
 68→type pickerItemType int
 69→
 70→const (
 71→	pickerItemSession pickerItemType = iota
 72→	pickerItemHeader
 73→)
 74→
 75→// pickerItem is an entry in the flattened picker list.
 76→type pickerItem struct {
 77→	typ      pickerItemType
 78→	session  *parser.SessionInfo // nil for headers
 79→	category parser.DateCategory // set for headers
 80→}
 81→
 82→// rebuildPickerItems flattens sessions into headers + session rows.
 83→// Within each date group, ongoing sessions sort first (stable sort preserves
 84→// mod-time order from DiscoverProjectSessions).
 85→func rebuildPickerItems(sessions []parser.SessionInfo) []pickerItem {
 86→	groups := parser.GroupSessionsByDate(sessions)
 87→
 88→	var items []pickerItem
 89→	for _, g := range groups {
 90→		items = append(items, pickerItem{
 91→			typ:      pickerItemHeader,
 92→			category: g.Category,
 93→		})
 94→
 95→		// Stable sort: ongoing first within each group.
 96→		sorted := make([]parser.SessionInfo, len(g.Sessions))
 97→		copy(sorted, g.Sessions)
 98→		sort.SliceStable(sorted, func(i, j int) bool {
 99→			if sorted[i].IsOngoing != sorted[j].IsOngoing {
100→				return sorted[i].IsOngoing
101→			}
102→			return false
103→		})
104→
105→		for i := range sorted {
106→			items = append(items, pickerItem{
107→				typ:     pickerItemSession,
108→				session: &sorted[i],
109→			})
110→		}
111→	}
112→	return items
113→}
