22→export function ProjectTree({
23→  sessions,
24→  selectedProject,
25→  highlightedIndex,
26→  isFocused,
27→}: ProjectTreeProps) {
28→  const entries = useProjectEntries(sessions);
29→  // Dynamic width: min 24, adapts to longest entry
30→  // Allow up to 40% of terminal width for sidebar, min 28
31→  const termCols = process.stdout.columns || 80;
32→  const maxWidth = Math.floor(termCols * 0.4);
33→  const contentWidth = Math.max(
34→    28,
35→    ...entries.map((e) => e.name.length + e.depth * 2 + String(e.count).length + 8),
36→  );
37→  const sidebarWidth = Math.min(maxWidth, contentWidth);
38→
39→  return (
40→    <Box
41→      flexDirection="column"
42→      borderStyle="single"
43→      borderColor={isFocused ? colors.accent : colors.border}
44→      width={sidebarWidth}
45→    >
