47→      <Box paddingX={1}>
48→        <Text bold dimColor>
49→          Projects
50→        </Text>
51→      </Box>
52→
53→      {/* Tree items */}
54→      {entries.map((item, idx) => {
55→        const isSelected =
56→          !item.isGroup &&
57→          (item.key === selectedProject || (item.key === null && selectedProject === null));
58→        const isHighlighted = isFocused && idx === highlightedIndex;
59→        const indent = "  ".repeat(item.depth);
60→        const branch = item.depth > 0 ? "└ " : "";
61→        const icon = isSelected && !item.isGroup ? "▸" : " ";
62→        const label = item.isGroup ? `⑃ ${item.name}` : item.name;
63→
64→        return (
65→          <Box key={item.key ?? "__all__"} flexDirection="column">
