16→export function statsFromMessage(msg: DisplayMessage): Stats {
17→  const agentCount = msg.items.filter(
18→    (it) => it.item_type === "Subagent" || it.subagent_messages.length > 0,
19→  ).length;
20→  return {
21→    tokens: msg.tokens_raw,
22→    toolCount: msg.tool_call_count,
23→    thinkingCount: msg.thinking_count,
24→    outputCount: msg.output_count,
25→    durationMs: msg.duration_ms,
26→    agentCount,
27→    spawnCount: msg.teammate_spawns,
28→  };
29→}
