 49→  const [sidebarHighlight, setSidebarHighlight] = useState(0);
 50→
 51→  const projectEntries = useProjectEntries(allSessions);
 52→
 53→  const pickerSessions = useMemo(() => {
 54→    if (selectedProject === null) return allSessions;
