 56→  }, [allSessions, selectedProject]);
 57→
 58→  useEffect(() => {
 59→    let cancelled = false;
 60→    const attempt = async (retries: number): Promise<void> => {
 61→      try {
 62→        const d = await api.getProjectDirs();
