213→        if (entry && !entry.isGroup) handleSelectProject(entry.key);
214→      } else if (input === "l" || key.rightArrow || key.escape) {
215→        setSidebarFocused(false);
216→      } else if (input === "q") {
217→        exit();
218→      }
219→      return;
220→    }
221→
222→    switch (view) {
223→      case "list": {
224→        if (input === "h" || key.leftArrow) {
225→          setSidebarFocused(true);
226→        } else if (input === "j" || key.downArrow) {
227→          setSelectedMessage((i) => Math.min(i + 1, messages.length - 1));
228→        } else if (input === "k" || key.upArrow) {
229→          setSelectedMessage((i) => Math.max(i - 1, 0));
230→        } else if (input === "G") {
231→          setSelectedMessage(messages.length - 1);
232→        } else if (input === "g") {
233→          setSelectedMessage(0);
234→        } else if (key.tab) {
235→          expandedMessages.toggle(selectedMessage);
236→        } else if (key.return) {
237→          if (messages.length > 0 && messages[selectedMessage]) {
238→            setSelectedItem(0);
239→            expandedItems.clear();
240→            setSubagentItem(null);
241→            setSubagentDetailMsg(null);
242→            setView("detail");
243→          }
244→        } else if (input === "e") {
245→          const indices: number[] = [];
246→          messages.forEach((m, i) => {
247→            if (m.role === "claude") indices.push(i);
248→          });
249→          expandedMessages.addAll(indices);
250→        } else if (input === "c") {
251→          expandedMessages.clear();
252→        } else if (input === "t") {
253→          if (teams.length > 0) setView("team");
254→        } else if (input === "d") {
255→          if (sessionPath) {
256→            api
257→              .getDebugLog(sessionPath)
258→              .then(setDebugEntries)
259→              .catch(() => {});
260→            setDebugSelected(0);
261→            setView("debug");
262→          }
263→        } else if (input === "q" || key.escape) {
