265→        }
266→        break;
267→      }
268→      case "detail": {
269→        if (subagentItem && !subagentDetailMsg) {
270→          // Viewing subagent message list
271→          const msgs = subagentItem.subagent_messages;
272→          if (input === "j" || key.downArrow) {
273→            setSubagentMsgIdx((i) => Math.min(i + 1, msgs.length - 1));
274→          } else if (input === "k" || key.upArrow) {
275→            setSubagentMsgIdx((i) => Math.max(i - 1, 0));
276→          } else if (key.return) {
277→            // Enter a message to see its items
278→            if (msgs[subagentMsgIdx]) {
279→              setSubagentDetailMsg(msgs[subagentMsgIdx]);
280→              setSelectedItem(0);
281→              expandedItems.clear();
282→            }
283→          } else if (input === "q" || key.escape) {
284→            setSubagentItem(null);
285→            setSubagentMsgIdx(0);
286→          }
287→        } else if (subagentDetailMsg) {
288→          // Viewing items of a subagent message
289→          const items = subagentDetailMsg.items || [];
290→          if (input === "j" || key.downArrow) {
291→            setSelectedItem((i) => Math.min(i + 1, items.length - 1));
292→          } else if (input === "k" || key.upArrow) {
293→            setSelectedItem((i) => Math.max(i - 1, 0));
294→          } else if (key.tab || key.return) {
295→            const item = items[selectedItem];
296→            if (key.return && item?.subagent_messages?.length > 0) {
297→              // Nested subagent — drill deeper
298→              setSubagentItem(item);
299→              setSubagentDetailMsg(null);
300→              setSubagentMsgIdx(0);
301→            } else {
302→              expandedItems.toggle(selectedItem);
303→            }
304→          } else if (input === "e") {
305→            expandedItems.addAll(items.map((_it, i) => i));
306→          } else if (input === "c") {
307→            expandedItems.clear();
308→          } else if (input === "q" || key.escape) {
309→            // Back to subagent message list
310→            setSubagentDetailMsg(null);
311→            setSubagentMsgIdx(0);
312→          }
313→        } else {
314→          // Top-level detail view (main message items)
315→          const items = messages[selectedMessage]?.items || [];
316→          if (input === "j" || key.downArrow) {
317→            setSelectedItem((i) => Math.min(i + 1, items.length - 1));
318→          } else if (input === "k" || key.upArrow) {
319→            setSelectedItem((i) => Math.max(i - 1, 0));
320→          } else if (key.tab) {
321→            expandedItems.toggle(selectedItem);
322→          } else if (key.return) {
323→            const item = items[selectedItem];
324→            if (item?.subagent_messages?.length > 0) {
325→              setSubagentItem(item);
326→              setSubagentMsgIdx(0);
327→              setSubagentDetailMsg(null);
328→            } else {
329→              expandedItems.toggle(selectedItem);
330→            }
331→          } else if (input === "e") {
332→            expandedItems.addAll(items.map((_it, i) => i));
333→          } else if (input === "c") {
334→            expandedItems.clear();
335→          } else if (input === "q" || key.escape) {
336→            setView("list");
337→          }
338→        }
339→        break;
340→      }
341→      case "debug": {
342→        if (input === "j" || key.downArrow) {
343→          setDebugSelected((i) => Math.min(i + 1, debugEntries.length - 1));
344→        } else if (input === "k" || key.upArrow) {
345→          setDebugSelected((i) => Math.max(i - 1, 0));
346→        } else if (input === "q" || key.escape) {
347→          setView("list");
348→        }
349→        break;
350→      }
351→      case "team": {
352→        if (input === "q" || key.escape) setView("list");
353→        break;
354→      }
355→      case "picker": {
356→        if (input === "h" || key.leftArrow) setSidebarFocused(true);
357→        else if (input === "j" || key.downArrow) {
358→          setPickerSelected((i) => Math.min(i + 1, pickerSessions.length - 1));
359→        } else if (input === "k" || key.upArrow) {
360→          setPickerSelected((i) => Math.max(i - 1, 0));
361→        } else if (input === "G") {
362→          setPickerSelected(pickerSessions.length - 1);
363→        } else if (input === "g") {
364→          setPickerSelected(0);
365→        } else if (key.return) {
366→          if (pickerSessions[pickerSelected]) {
367→            handleSelectSession(pickerSessions[pickerSelected]);
368→          }
369→        } else if (input === "q") {
370→          exit();
371→        }
372→        break;
373→      }
374→    }
375→  };
376→  // Stable function reference — never changes, so Ink's useInput effect never re-subscribes.
377→  const stableHandler = useCallback((input: string, key: Key) => {
378→    inputHandlerRef.current(input, key);
379→  }, []);
380→  useInput(stableHandler);
381→
382→  // ---- Render ----
383→  const renderView = () => {
384→    switch (view) {
385→      case "picker":
386→        return (
387→          <SessionPicker
388→            sessions={pickerSessions}
389→            loading={pickerLoading}
390→            error={pickerError}
391→            selectedIndex={pickerSelected}
392→          />
393→        );
394→      case "list":
395→        if (loading) {
396→          return (
397→            <Box padding={1}>
398→              <Spinner label="Loading session..." />
399→            </Box>
400→          );
401→        }
402→        return (
403→          <MessageList
404→            messages={messages}
405→            selectedIndex={selectedMessage}
406→            expandedSet={expandedMessages.set}
407→            ongoing={ongoing}
408→          />
409→        );
410→      case "detail": {
411→        if (subagentItem && !subagentDetailMsg) {
412→          // Show subagent's messages as a list
413→          return (
414→            <MessageList
415→              messages={subagentItem.subagent_messages}
416→              selectedIndex={subagentMsgIdx}
417→              expandedSet={expandedMessages.set}
418→              ongoing={subagentItem.subagent_ongoing}
419→            />
420→          );
421→        }
422→        if (subagentDetailMsg) {
423→          // Show a subagent message's items
424→          return (
425→            <DetailView
426→              message={subagentDetailMsg}
427→              selectedItem={selectedItem}
428→              expandedItems={expandedItems.set}
429→              ongoing={false}
430→              depth={1}
431→            />
432→          );
433→        }
434→        // Top-level message detail
435→        if (messages[selectedMessage]) {
436→          return (
437→            <DetailView
438→              message={messages[selectedMessage]}
439→              selectedItem={selectedItem}
440→              expandedItems={expandedItems.set}
441→              ongoing={ongoing && selectedMessage === messages.length - 1}
442→            />
443→          );
444→        }
445→        return null;
446→      }
447→      case "team":
448→        return <TeamBoard teams={teams} />;
449→      case "debug":
450→        return <DebugViewer entries={debugEntries} selectedIndex={debugSelected} />;
451→    }
452→  };
453→
454→  const termHeight = process.stdout.rows || 24;
455→
456→  return (
457→    <Box flexDirection="column" height={termHeight}>
458→      {sessionPath && view !== "picker" && (
459→        <InfoBar
460→          meta={meta}
