486→            : view === "detail"
487→              ? subagentItem && !subagentDetailMsg
488→                ? `agent ${subagentMsgIdx + 1}/${subagentItem.subagent_messages.length}`
489→                : `${subagentDetailMsg ? "agent " : ""}${selectedItem + 1}/${(subagentDetailMsg ?? messages[selectedMessage])?.items.length || 0}`
490→              : view === "debug"
491→                ? `${debugSelected + 1}/${debugEntries.length}`
492→                : view === "picker"
