 12→function limitLines(text: string, maxLines: number): string {
 13→  const lines = text.split("\n");
 14→  if (lines.length <= maxLines) return text;
 15→  return lines.slice(0, maxLines).join("\n") + "\n…(" + (lines.length - maxLines) + " more lines)";
 16→}
 17→
 18→/** Clamp each line to maxWidth so bordered boxes don't overflow the terminal. */
 19→function clampLines(text: string, maxWidth: number): string {
