export function TeamBoard({ teams }: TeamBoardProps) {
  if (teams.length === 0) {
    return (
      <Box paddingX={1}>
        <Text dimColor>No active teams</Text>
      </Box>
    );
  }

  return (
    <Box flexDirection="column" paddingX={1}>
      <Box marginBottom={1}>
        <Text bold>Teams ({teams.length})</Text>
      </Box>

